'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { motion } from 'framer-motion';
import { HiOutlineArrowLeft, HiOutlinePaperAirplane } from 'react-icons/hi';
import { doc, setDoc, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { generateCodeName } from '@/lib/codenames';
import { UserProfile } from '@/lib/types';

const SECTIONS = ['projects', 'skills', 'interests', 'working-style'];
const SECTION_TITLES = ['Past Projects', 'Core Skills', 'Your Interests', 'Working Style'];

interface Message {
    role: 'user' | 'assistant';
    content: string;
}

export default function OnboardChatPage() {
    const { user, profile, loading, refreshProfile } = useAuth();
    const router = useRouter();

    const [currentSectionIndex, setCurrentSectionIndex] = useState(0);
    const [messages, setMessages] = useState<Message[]>([]);
    const [input, setInput] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const [isExtracting, setIsExtracting] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const section = SECTIONS[currentSectionIndex];

    useEffect(() => {
        if (!loading && !user) router.push('/auth');
    }, [user, loading, router]);

    // Initial greeting for the first section
    useEffect(() => {
        if (messages.length === 0 && !isTyping && !isExtracting) {
            fetchNextQuestion([]);
        }
    }, [currentSectionIndex]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages, isTyping]);

    const fetchNextQuestion = async (history: Message[]) => {
        setIsTyping(true);
        try {
            const res = await fetch('/api/nim', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    action: 'onboard-message',
                    payload: { conversationHistory: history, section },
                }),
            });
            const data = await res.json();
            if (data.reply) {
                setMessages((prev) => [...prev, { role: 'assistant', content: data.reply }]);
            }
        } catch (error) {
            console.error('Failed to fetch next question:', error);
        } finally {
            setIsTyping(false);
        }
    };

    const handleSend = async () => {
        if (!input.trim() || isTyping) return;
        const userMsg: Message = { role: 'user', content: input.trim() };
        const newHistory = [...messages, userMsg];
        setMessages(newHistory);
        setInput('');
        await fetchNextQuestion(newHistory);
    };

    const handleNextSection = () => {
        if (currentSectionIndex < SECTIONS.length - 1) {
            setCurrentSectionIndex((prev) => prev + 1);
        } else {
            finishOnboarding();
        }
    };

    const finishOnboarding = async () => {
        if (!user) return;
        setIsExtracting(true);
        try {
            // Create a full transcript of the conversation
            const conversationText = messages
                .map((m) => `${m.role === 'user' ? 'Student' : 'Assistant'}: ${m.content}`)
                .join('\n');

            // 1. Extract Profile using NIM
            const res = await fetch('/api/nim', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    action: 'extract-profile',
                    payload: { conversationText },
                }),
            });
            const data = await res.json();
            const st = data.extracted;

            if (!st || st.error) throw new Error('Failed to extract profile');

            // 2. Save to Firestore
            const codeName = profile?.codeName || generateCodeName();

            const userData: UserProfile = {
                uid: user.uid,
                codeName,
                email: profile?.email || '',
                phone: user.phoneNumber || '',
                realName: profile?.realName || '',
                aboutMe: st.bio || profile?.aboutMe || '',
                headline: st.headline || profile?.headline || '',
                techSkills: (st.hard_skills || []).map((s: any) => s.name),
                nonTechSkills: (st.soft_skills || []).map((s: any) => s.name),
                interests: (st.interests || []).map((s: any) => s.name),
                availabilityHoursPerWeek: st.availability_hours_per_week || 10,
                workingStyle: st.working_style || { pace: 'short-term', collaboration: 'mixed', risk: 'medium', leadership: 'either' },

                // Preserve existing or default empty
                projects: profile?.projects || [],
                papers: profile?.papers || 0,
                patents: profile?.patents || 0,
                competitions: profile?.competitions || [],
                certifications: profile?.certifications || [],
                cgpa: profile?.cgpa || 0,
                internships: profile?.internships || [],
                age: profile?.age || 18,
                hackathons: profile?.hackathons || [],
                collaborationCount: profile?.collaborationCount || 0,
                github: profile?.github || '',
                linkedin: profile?.linkedin || '',
                codechef: profile?.codechef || '',
                leetcode: profile?.leetcode || '',
                hackerrank: profile?.hackerrank || '',
                college: profile?.college || '',
                rating: profile?.rating || 5.0,
                score: Object.keys(st).length, // simple score
                reports: profile?.reports || [],
                dateJoined: profile?.dateJoined || new Date().toISOString(),
                isActive: true,
                isStudent: true,
                profileCompleted: true,
            };

            await setDoc(doc(db, 'users', user.uid), userData, { merge: true });

            // 3. Upsert to Pinecone
            await fetch('/api/pinecone', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    action: 'upsert-candidate',
                    payload: { uid: user.uid, profile: userData },
                }),
            });

            await refreshProfile();
            router.push('/swipe');
        } catch (error) {
            console.error('Error extracting profile:', error);
            alert('Something went wrong interpreting your profile. Please try again.');
        } finally {
            setIsExtracting(false);
        }
    };

    if (loading || !user) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-white">
                <motion.div
                    animate={{ rotate: 360 }}
                    transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
                    className="w-8 h-8 border-2 border-black border-t-transparent rounded-full"
                />
            </div>
        );
    }

    if (isExtracting) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center bg-white px-6 text-center space-y-6">
                <motion.div
                    animate={{ scale: [1, 1.1, 1] }}
                    transition={{ repeat: Infinity, duration: 2, ease: 'easeInOut' }}
                    className="w-16 h-16 bg-black rounded-2xl flex items-center justify-center shadow-2xl"
                >
                    <span className="text-white text-2xl">✨</span>
                </motion.div>
                <div>
                    <h2 className="text-xl font-bold tracking-tight mb-2">Analyzing your profile...</h2>
                    <p className="text-sm text-gray-500 max-w-xs mx-auto">
                        Our AI is reading through your conversation and building your structured Nexus profile.
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            {/* Header */}
            <div className="sticky top-0 bg-white/90 backdrop-blur-lg z-10 border-b border-gray-100 px-6 py-4 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => router.back()}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 transition-colors"
                    >
                        <HiOutlineArrowLeft className="text-lg" />
                    </button>
                    <div>
                        <h1 className="text-sm font-bold tracking-tight">Nexus AI Onboarding</h1>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
                            Part {currentSectionIndex + 1} of {SECTIONS.length}: {SECTION_TITLES[currentSectionIndex]}
                        </p>
                    </div>
                </div>
                <button
                    onClick={handleNextSection}
                    disabled={isTyping || messages.length < 2}
                    className="text-xs font-bold text-black border border-gray-200 px-3 py-1.5 rounded-full hover:bg-black hover:text-white transition-all disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:text-black"
                >
                    {currentSectionIndex < SECTIONS.length - 1 ? 'Next Topic →' : 'Finish Setup'}
                </button>
            </div>

            {/* Chat Area */}
            <div className="flex-1 overflow-y-auto px-4 py-6 space-y-4 pb-32">
                {messages.map((msg, idx) => (
                    <motion.div
                        key={idx}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                    >
                        <div
                            className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${msg.role === 'user'
                                    ? 'bg-black text-white rounded-tr-sm'
                                    : 'bg-white border border-gray-100 text-gray-800 rounded-tl-sm shadow-sm'
                                }`}
                        >
                            {msg.content}
                        </div>
                    </motion.div>
                ))}

                {isTyping && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex justify-start">
                        <div className="bg-white border border-gray-100 rounded-2xl rounded-tl-sm px-4 py-3 flex items-center gap-1 shadow-sm">
                            <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                            <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                            <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                        </div>
                    </motion.div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Box */}
            <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 p-4 safe-bottom">
                <div className="max-w-lg mx-auto relative flex items-center">
                    <textarea
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                                e.preventDefault();
                                handleSend();
                            }
                        }}
                        placeholder={isTyping ? 'Assistant is typing...' : 'Type your answer...'}
                        disabled={isTyping}
                        rows={1}
                        className="w-full bg-gray-50 border border-gray-200 rounded-full pl-5 pr-12 py-3.5 text-sm focus:outline-none focus:border-black focus:ring-1 focus:ring-black min-h-[48px] max-h-32 resize-none transition-all disabled:opacity-50"
                    />
                    <button
                        onClick={handleSend}
                        disabled={!input.trim() || isTyping}
                        className="absolute right-2 top-1/2 -translate-y-1/2 w-9 h-9 bg-black text-white rounded-full flex items-center justify-center disabled:opacity-30 disabled:bg-gray-200 disabled:text-gray-400 transition-colors"
                    >
                        <HiOutlinePaperAirplane className="rotate-90 ml-0.5 text-sm" />
                    </button>
                </div>
            </div>
        </div>
    );
}
